// drawing.js
import * as d3 from "d3";
import { showBackground } from "./ui.js";
import { imagePaths } from "./backgrounds.js";
import * as AppUI from "./ui.js";

export function createSvgAndContainer() {
  const svgToBrowserRatio = 1; // 0.95;
  const browserCanvasWidth  = window.innerWidth;
  const width  = browserCanvasWidth * svgToBrowserRatio;
  const browserCanvasHeight = window.visualViewport ? window.visualViewport.height : window.innerHeight;
  const height = browserCanvasHeight * svgToBrowserRatio;
  const minDim = Math.min(width, height);
  const scaleUnit = minDim/180;

  if(window.visualViewport.height > (window.innerHeight+2)) {
    console.log("user appears to be on mobile. good luck.", "pink"); 
    console.log('height: ' + height, "pink"); 
    console.log('window.visualViewport.height: ' + window.visualViewport.height, "pink"); 
    console.log('(window.innerHeight+2): ' + (window.innerHeight+2), "pink");
  }
  const svg = d3.select("body")
    .append("svg")
    .attr("xmlns","http://www.w3.org/2000/svg")
    .attr("width", width)
    .attr("height", height);
  
  const container = svg.append("g")
    .attr("class", "container")
    .attr("transform", `translate(${browserCanvasWidth/2},${browserCanvasHeight/2})`);

  const backgroundLayer = container.append("g")
    .attr("id", "background-layer")
    .attr("class", showBackground.boolState ? showBackground.DOMObjectString+"" : showBackground.DOMObjectString+" hidden");
    imagePaths.forEach((imagePath) => {
        backgroundLayer.append("image")
          .attr("opacity", imagePath.opacity)
          .attr("data-background-name", imagePath.name)
          .attr("href", imagePath.url)
          .attr("width", imagePath.width * scaleUnit)
          .attr("height", imagePath.height * scaleUnit)
          .attr("x", imagePath.x * scaleUnit)
          .attr("y", imagePath.y * scaleUnit);
    });

    
  const hotspotLayer = container.append("g")
  .attr("class", "hotspot-layer")
  .attr("id", "hotspot-layer");
  
  // Layer for explicit node-to-node links (spawn preset arrows)
  const linkLayer = container.append("g")
  .attr("class", "node-links")
  .attr("id", "node-links");
  
  const windLayerCancel = container.append("g")
  .attr("class", AppUI.showWindCancel.DOMObjectString)
  .attr("id", AppUI.showWindCancel.DOMObjectString)
  .attr("style","transition: all ease-in-out 2s;")
  ;
  const windLayerStress = container.append("g")
  .attr("class", AppUI.showWindStress.DOMObjectString)
  .attr("id", AppUI.showWindStress.DOMObjectString)
  .attr("style","transition: all ease-in-out 2s;")
  ;
  const windLayerNetForceArrows = container.append("g")
  .attr("class", AppUI.showWindNetForceArrows.DOMObjectString)
  .attr("id", AppUI.showWindNetForceArrows.DOMObjectString)
  .attr("style","transition: all ease-in-out 2s;")
  ;

  const nodeLayer = container.append("g")
  .attr("class", "node-layer")
  .attr("id", "node-layer");

  return { svg, container, nodeLayer, hotspotLayer, linkLayer, windLayerCancel, windLayerStress, windLayerNetForceArrows, width, height, minDim, scaleUnit };
}

export function createAxes(container, width, height, minDim) {
  const domainExtent = 90;

  const yScale = d3.scaleLinear()
    .domain([-domainExtent, domainExtent])
    .range([ minDim/2, -minDim/2 ]);

  const xScale = d3.scaleLinear()
    .domain([-domainExtent, domainExtent])
    .range([-minDim/2, minDim/2]);

  const yAxis = d3.axisLeft(yScale).ticks(10);
  const xAxis = d3.axisBottom(xScale).ticks(10);

  const axisContainer = container.append("g").attr("class","axis");
  axisContainer.append("g")
    .attr("class", "y-axis")
    .call(yAxis);

    axisContainer.append("g")
    .attr("class", "x-axis")
    .call(xAxis);

  return { xScale, yScale, xAxis, yAxis };
}

/** Vertical lines every 10 data units; horizontal lines every 10. Groups have class "grid-vertical" and "grid-horizontal" for UI toggles. */
export function createGridLines(container, xScale, yScale) {
  const domainExtent = 90;
  const step = 10;
  const positions = d3.range(-domainExtent, domainExtent + 1, step);

  const vertGroup = container.append("g").attr("class", "grid-vertical");
  vertGroup.selectAll("line")
    .data(positions)
    .join("line")
    .attr("x1", d => xScale(d))
    .attr("x2", d => xScale(d))
    .attr("y1", yScale(-domainExtent))
    .attr("y2", yScale(domainExtent))
    .attr("stroke", "currentColor")
    .attr("stroke-opacity", 0.25)
    .attr("stroke-width", 1);

  const horizGroup = container.append("g").attr("class", "grid-horizontal");
  horizGroup.selectAll("line")
    .data(positions)
    .join("line")
    .attr("x1", xScale(-domainExtent))
    .attr("x2", xScale(domainExtent))
    .attr("y1", d => yScale(d))
    .attr("y2", d => yScale(d))
    .attr("stroke", "currentColor")
    .attr("stroke-opacity", 0.25)
    .attr("stroke-width", 1);

  return { vertGroup, horizGroup };
}

export function createGrid(container, width, height, minDim, gridSpacing=2) {
  const domainExtent = 90;

  const yScale = d3.scaleLinear()
    .domain([-domainExtent, domainExtent])
    .range([ minDim/2, -minDim/2 ]);

  const xScale = d3.scaleLinear()
    .domain([-domainExtent, domainExtent])
    .range([-minDim/2, minDim/2]);

  const yAxis = d3.axisLeft(yScale).ticks(10);
  const xAxis = d3.axisBottom(xScale).ticks(10);

  const axisContainer = container.append("g").attr("class","axis");
  axisContainer.append("g")
    .attr("class", "y-axis")
    .call(yAxis);

    axisContainer.append("g")
    .attr("class", "x-axis")
    .call(xAxis);

  return { xScale, yScale, xAxis, yAxis };
}

export function createArrowheads(defs, colours) {
  const arrowsContainer = defs.append("g").attr("id","arrows").attr("class","arrows");
  arrowsContainer.append("marker")
    .attr("id", "arrowhead-white")
    .attr("viewBox", "0 0 10 10")
    .attr("refX", 0)
    .attr("refY", 5)
    .attr("markerWidth", 4)
    .attr("markerHeight", 4)
    .attr("orient", "auto")
    .append("path")
    .attr("d", "M0,0 L10,5 L0,10 Z")
    .attr("fill", "white");

  // Generic black arrowhead (used for node-links)
  arrowsContainer.append("marker")
    .attr("id", "arrowhead-black")
    .attr("viewBox", "0 0 10 10")
    .attr("refX", 0)
    .attr("refY", 5)
    .attr("markerWidth", 4)
    .attr("markerHeight", 4)
    .attr("orient", "auto")
    .append("path")
    .attr("d", "M0,0 L10,5 L0,10 Z")
    .attr("fill", "black");

  // Define gradients for each node's hotspots dynamically
  colours.forEach(colour => {
    arrowsContainer.append("marker")
    .attr("id", "arrowhead-"+colour)
    .attr("viewBox", "0 0 10 10")
    .attr("refX", 0)
    .attr("refY", 5)
    .attr("markerWidth", 4)
    .attr("markerHeight", 4)
    .attr("orient", "auto")
    .append("path")
    .attr("d", "M0,0 L10,5 L0,10 L2,5 Z")
    .attr("fill", colour);

  });


}
